// Validate input parameters
const input = $input.first().json;

if (!input.prompt) {
  throw new Error('Prompt is required');
}

if (!input.context) {
  input.context = {};
}

if (!input.outputFormat) {
  input.outputFormat = 'json';
}

return {
  prompt: input.prompt,
  context: input.context,
  outputFormat: input.outputFormat,
  role: input.role || 'Tech LEAD',
  task: input.task || 'general'
};

// Build Claude prompt with context
const { prompt, context, role, task } = $input.first().json;

let systemPrompt = `You are ${role}, an intelligent technical leader and orchestrator.`;

if (task === 'issue_selection') {
  systemPrompt += `\n\nYour task is to analyze GitHub issues and select the most appropriate one to work on next.`;
  systemPrompt += `\nConsider: priority labels, issue age, complexity, dependencies, and project goals.`;
  systemPrompt += `\nReturn JSON format: {selected_issue: number, reasoning: string, estimated_hours: number, priority: 'high'|'medium'|'low'}`;
} else if (task === 'review_filter') {
  systemPrompt += `\n\nYour task is to analyze code review feedback and extract actionable items.`;
  systemPrompt += `\nIdentify critical issues that must be addressed vs suggestions.`;
  systemPrompt += `\nReturn JSON format: {needs_changes: boolean, critical_issues: [], suggestions: [], ready_to_merge: boolean}`;
} else if (task === 'error_analysis') {
  systemPrompt += `\n\nYour task is to analyze error messages and suggest solutions.`;
  systemPrompt += `\nProvide clear, actionable steps to resolve the issue.`;
  systemPrompt += `\nReturn JSON format: {error_type: string, likely_cause: string, suggested_fix: string, commands: []}`;
}

const fullPrompt = {
  system: systemPrompt,
  context: JSON.stringify(context),
  user_prompt: prompt,
  output_format: $input.first().json.outputFormat
};

return fullPrompt;

// Parse and validate Claude response
const response = $input.first().json;
const outputFormat = $node['validate-input'].json.outputFormat;

let parsedResponse;

if (outputFormat === 'json') {
  try {
    // If response is already JSON
    if (typeof response === 'object') {
      parsedResponse = response;
    } else if (typeof response === 'string') {
      parsedResponse = JSON.parse(response);
    } else if (response.output) {
      parsedResponse = JSON.parse(response.output);
    }
  } catch (error) {
    throw new Error(`Failed to parse Claude JSON response: ${error.message}`);
  }
} else {
  // Text response
  parsedResponse = response.output || response;
}

// Add metadata
return {
  success: true,
  task: $node['validate-input'].json.task,
  response: parsedResponse,
  timestamp: new Date().toISOString()
};

// Return formatted result
const result = $node['parse-response'].json;

return {
  success: result.success,
  data: result.response,
  metadata: {
    task: result.task,
    timestamp: result.timestamp,
    logged: true
  }
};

// Error handler
const error = $input.first().json.error || $input.first().json;

// Log error to database
return {
  success: false,
  error: {
    message: error.message || 'Unknown error',
    stack: error.stack,
    timestamp: new Date().toISOString()
  },
  recovery_suggestions: [
    'Check Claude CLI authentication',
    'Verify input format',
    'Check network connectivity',
    'Review Claude API limits'
  ]
};
